/**
 * Implements a Min Priority Queue using a Binary Heap structure.
 * Stores [cost (BigInt), index (Number)].
 */
class PriorityQueue {
    constructor() {
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    // Compares based on cost (BigInt)
    compare(i, j) {
        return this.heap[i][0] < this.heap[j][0];
    }

    swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    getParentIndex(i) { return Math.floor((i - 1) / 2); }
    getLeftChildIndex(i) { return 2 * i + 1; }
    getRightChildIndex(i) { return 2 * i + 2; }

    enqueue(element) {
        this.heap.push(element);
        this.bubbleUp(this.heap.length - 1);
    }

    bubbleUp(index) {
        let currentIndex = index;
        while (currentIndex > 0) {
            const parentIndex = this.getParentIndex(currentIndex);
            if (this.compare(currentIndex, parentIndex)) {
                this.swap(currentIndex, parentIndex);
                currentIndex = parentIndex;
            } else {
                break;
            }
        }
    }

    dequeue() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const min = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.bubbleDown(0);
        return min;
    }

    bubbleDown(index) {
        let currentIndex = index;
        const lastIndex = this.heap.length - 1;

        while (true) {
            let leftChildIndex = this.getLeftChildIndex(currentIndex);
            let rightChildIndex = this.getRightChildIndex(currentIndex);
            let smallest = currentIndex;

            // Check left child
            if (leftChildIndex <= lastIndex && this.compare(leftChildIndex, smallest)) {
                smallest = leftChildIndex;
            }

            // Check right child
            if (rightChildIndex <= lastIndex && this.compare(rightChildIndex, smallest)) {
                smallest = rightChildIndex;
            }

            if (smallest !== currentIndex) {
                this.swap(currentIndex, smallest);
                currentIndex = smallest;
            } else {
                break;
            }
        }
    }
}


function solve(nums, queries) {
    const N = nums.length;
    if (N === 0) return [];

    // --- Step 1: Precalculate C[x] = closest(x) ---
    const C = new Array(N);

    for (let x = 0; x < N; x++) {
        if (x === 0) {
            C[x] = 1;
            continue;
        }
        if (x === N - 1) {
            C[x] = N - 2;
            continue;
        }

        // 0 < x < N-1
        // Check neighbors x-1 and x+1

        // Differences (since nums is strictly increasing)
        const DL = BigInt(nums[x]) - BigInt(nums[x-1]);
        const DR = BigInt(nums[x+1]) - BigInt(nums[x]);

        // If DL <= DR, choose x-1 (smaller index due to tie breaker)
        if (DL <= DR) {
            C[x] = x - 1;
        } else {
            C[x] = x + 1;
        }
    }

    /**
     * Runs Dijkstra's algorithm from a starting node s.
     * Returns an array D where D[i] is the minimum cost from s to i.
     * Costs are BigInt.
     */
    const dijkstra = (start_node) => {
        const INF = 10n ** 30n; // A sufficiently large BigInt infinity
        const D = new Array(N).fill(INF);
        const pq = new PriorityQueue();

        D[start_node] = 0n;
        pq.enqueue([0n, start_node]);

        while (!pq.isEmpty()) {
            const [d, x] = pq.dequeue();

            if (d > D[x]) {
                continue;
            }

            // 1. Type 2 move (to closest) - Cost 1
            const y_closest = C[x];
            const cost_T2 = 1n;

            if (D[x] + cost_T2 < D[y_closest]) {
                D[y_closest] = D[x] + cost_T2;
                pq.enqueue([D[y_closest], y_closest]);
            }

            // 2. Type 1 moves (to all y) - Cost |nums[x] - nums[y]|
            const Nx = BigInt(nums[x]);

            for (let y = 0; y < N; y++) {
                if (x === y) continue;

                const Ny = BigInt(nums[y]);

                // Cost = |nums[x] - nums[y]|
                let cost_T1 = Ny > Nx ? Ny - Nx : Nx - Ny;

                if (D[x] + cost_T1 < D[y]) {
                    D[y] = D[x] + cost_T1;
                    pq.enqueue([D[y], y]);
                }
            }
        }
        return D;
    };

    const results = [];

    for (const [l, r] of queries) {
        // Since the graph structure is fixed, we run Dijkstra for each query starting at l.
        const distances = dijkstra(l);

        // The result for the query [l, r] is D[r]
        // We convert BigInt result back to string/Number if possible, but since the return type implies integer,
        // we assume standard JS Number can hold the result, although BigInt is safer for intermediate calculation.
        // Based on problem constraints and typical CP environment, we convert back to Number if it fits standard safe integer range.
        const finalCost = distances[r];

        if (finalCost === 10n ** 30n) {
             // Should not happen based on problem constraints (path always exists)
             results.push(0); 
        } else {
             results.push(Number(finalCost));
        }
    }

    return results;
}

